qry:select.qry:xquery:
for $r in sql(' SELECT {%? (#PARAMIN:@orden!=''){% {%= #PARAMIN:@orden %} as Orden,%}{% %} %} ACC01_ACCIDENTES.oi_personal_emp, ACC01_ACCIDENTES.f_fechahora_acc, ACC01_ACCIDENTES.oi_tipo_acc, ACC01_ACCIDENTES.oi_reg_cuerpo, ACC01_ACCIDENTES.oi_natur_lesion, ACC01_ACCIDENTES.oi_agente_caus, PER01_PERSONAL.d_ape_y_nom, PER02_PERSONAL_EMP.e_numero_legajo, ORG03_UBICACIONES.c_ubicacion, ORG03_UBICACIONES.d_ubicacion, ACC01_ACCIDENTES.f_fechahora_baja, ACC01_ACCIDENTES.f_fechahora_alta, ACC01_ACCIDENTES.e_dias_perdidos, ACC01_ACCIDENTES.o_accidente, ACC01_ACCIDENTES.oi_incapacidad, ACC01_ACCIDENTES.oi_elemento_pp, ACC13_TIP_SINIESTRO.d_tipo_siniestro FROM ACC01_ACCIDENTES, PER02_PERSONAL_EMP, PER01_PERSONAL, ORG03_UBICACIONES, ACC13_TIP_SINIESTRO JOIN ACC01_ACCIDENTES.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal, PER02_PERSONAL_EMP.oi_ubicacion LEFT OUTER ORG03_UBICACIONES.oi_ubicacion, ACC13_TIP_SINIESTRO.oi_tipo_siniestro LEFT OUTER ACC01_ACCIDENTES.oi_tipo_siniestro
WHERE PER02_PERSONAL_EMP.oi_empresa = {#PARAMIN:@oi_empresa} AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=#PARAMIN:@values%}) {%? (#PARAMIN:@f_desde!= '') {% AND ACC01_ACCIDENTES.f_fechahora_acc > {Datetime(#PARAMIN:@f_desde)} %} {% %} %} {%? (#PARAMIN:@f_hasta != '') {% AND ACC01_ACCIDENTES.f_fechahora_acc < {Datetime(Number(Datetime(#PARAMIN:@f_hasta))+1)} %} {% %} %} {%? (#PARAMIN:@oi_tipo_siniestro != '') {% AND ACC01_ACCIDENTES.oi_tipo_siniestro = {#PARAMIN:@oi_tipo_siniestro} %} {% %} %}
{%? (#PARAMIN:@orden!='') {%ORDER BY orden ASC %} {% %} %} ')/ROWS/ROW
